    [InlineData(Transactions::SourceCategory.InboundRealTimePaymentsTransferConfirmation)]
    [InlineData(Transactions::SourceCategory.InboundWireReversal)]
    [InlineData(Transactions::SourceCategory.InboundWireTransfer)]
    [InlineData(Transactions::SourceCategory.InboundWireTransferReversal)]
    [InlineData(Transactions::SourceCategory.InterestPayment)]
    [InlineData(Transactions::SourceCategory.InternalSource)]
    [InlineData(Transactions::SourceCategory.RealTimePaymentsTransferAcknowledgement)]
    [InlineData(Transactions::SourceCategory.SampleFunds)]
    [InlineData(Transactions::SourceCategory.WireTransferIntention)]
    [InlineData(Transactions::SourceCategory.SwiftTransferIntention)]
    [InlineData(Transactions::SourceCategory.SwiftTransferReturn)]
    [InlineData(Transactions::SourceCategory.CardPushTransferAcceptance)]
    [InlineData(Transactions::SourceCategory.AccountRevenuePayment)]
    [InlineData(Transactions::SourceCategory.BlockchainOnrampTransferIntention)]
    [InlineData(Transactions::SourceCategory.BlockchainOfframpTransferSettlement)]
    [InlineData(Transactions::SourceCategory.Other)]
    public void Validation_Works(Transactions::SourceCategory rawValue)
    {
        // force implicit conversion because Theory can't do that for us
        ApiEnum<string, Transactions::SourceCategory> value = rawValue;
        value.Validate();
    }

    [Fact]
    public void InvalidEnumValidationThrows_Works()
    {
        var value = JsonSerializer.Deserialize<ApiEnum<string, Transactions::SourceCategory>>(
            JsonSerializer.SerializeToElement("invalid value"),
            ModelBase.SerializerOptions
        );

        Assert.NotNull(value);
        Assert.Throws<IncreaseInvalidDataException>(() => value.Validate());
    }

    [Theory]
    [InlineData(Transactions::SourceCategory.AccountTransferIntention)]
    [InlineData(Transactions::SourceCategory.AchTransferIntention)]
    [InlineData(Transactions::SourceCategory.AchTransferRejection)]
    [InlineData(Transactions::SourceCategory.AchTransferReturn)]
    [InlineData(Transactions::SourceCategory.CashbackPayment)]
    [InlineData(Transactions::SourceCategory.CardDisputeAcceptance)]
    [InlineData(Transactions::SourceCategory.CardDisputeFinancial)]
    [InlineData(Transactions::SourceCategory.CardDisputeLoss)]
    [InlineData(Transactions::SourceCategory.CardRefund)]
    [InlineData(Transactions::SourceCategory.CardSettlement)]
    [InlineData(Transactions::SourceCategory.CardFinancial)]
    [InlineData(Transactions::SourceCategory.CardRevenuePayment)]
